    for (int i = 0; i < c1; i++) {
        strcpy(all_names[all_count++], fnames1[i]);
    }
    for (int i = 0; i < c2; i++) {
        int dup = 0;
        for (int j = 0; j < all_count; j++) {
            if (strcmp(all_names[j], fnames2[i]) == 0) { dup = 1; break; }
        }
        if (!dup) strcpy(all_names[all_count++], fnames2[i]);
